# Three Schema Architecture Implementation
# Level 1: Internal Schema (Physical Storage)
class InternalSchema:
    """Internal Level - How data is physically stored"""

    def __init__(self):
        self.storage = {}
        self.indexes = {}

    def store(self, table_name, data):
        # Simulates physical storage with indexing
        self.storage[table_name] = data
        self.indexes[table_name] = {i: i for i in range(len(data))}
        return True

    def retrieve(self, table_name):
        return self.storage.get(table_name, [])

# Level 2: Conceptual Schema (Logical Structure)
class ConceptualSchema:
    """Conceptual Level - Logical data structure and relationships"""

    def __init__(self):
        self.tables = {}
        self.relationships = {}

    def define_table(self, table_name, columns):
        self.tables[table_name] = columns

    def add_relationship(self, table1, table2, relation_type):
        self.relationships[f"{table1}-{table2}"] = relation_type

# Level 3: External Schema (User Views)
class ExternalSchema:
    """External Level - Different user views of the data"""

    def __init__(self, conceptual_schema):
        self.conceptual = conceptual_schema
        self.views = {}

    def create_view(self, view_name, table_name, visible_columns):
        self.views[view_name] = {
            'table': table_name,
            'columns': visible_columns
        }

# Demonstration
internal = InternalSchema()
conceptual = ConceptualSchema()
external = ExternalSchema(conceptual)

# Define logical structure
conceptual.define_table('students', ['id', 'name', 'age', 'gpa'])
conceptual.define_table('courses', ['id', 'name', 'credits'])
conceptual.add_relationship('students', 'courses', 'enrolled_in')

# Store data physically
internal.store('students', [
    {'id': 1, 'name': 'Alice', 'age': 20, 'gpa': 3.8},
    {'id': 2, 'name': 'Bob', 'age': 21, 'gpa': 3.5}
])

# Create user-specific views
external.create_view('student_directory', 'students', ['id', 'name'])
external.create_view('student_academics', 'students', ['id', 'gpa'])

print("=== Three Schema Architecture Demo ===")
print(f"Conceptual Schema: {conceptual.tables}")
print(f"External Views: {external.views}")
print(f"Internal Storage: {internal.retrieve('students')}")

# Schema Mapping and Transformation Engine
# Demonstrates data transformation between external, conceptual, and internal levels

class SchemaMapper:
    """Handles mapping between different schema levels"""

    def __init__(self):
        self.external_to_conceptual = {}
        self.conceptual_to_internal = {}

    def add_mapping(self, level_from, level_to, mapping_func):
        key = f"{level_from}_to_{level_to}"
        if level_from == 'external' and level_to == 'conceptual':
            self.external_to_conceptual[key] = mapping_func
        elif level_from == 'conceptual' and level_to == 'internal':
            self.conceptual_to_internal[key] = mapping_func

    def transform(self, data, from_level, to_level):
        key = f"{from_level}_to_{to_level}"
        if key in self.external_to_conceptual:
            return self.external_to_conceptual[key](data)
        elif key in self.conceptual_to_internal:
            return self.conceptual_to_internal[key](data)
        return data

# Define the database with all three levels
class ThreeLevelDatabase:
    """Complete three-schema database implementation"""

    def __init__(self):
        self.mapper = SchemaMapper()
        self.setup_mappings()
        self.internal_data = {}

    def setup_mappings(self):
        # External to Conceptual: User view to logical structure
        self.mapper.add_mapping('external', 'conceptual', 
            lambda data: {'table': 'students', 'records': data})

        # Conceptual to Internal: Logical structure to physical storage
        self.mapper.add_mapping('conceptual', 'internal',
            lambda data: self._to_physical_format(data))

    def _to_physical_format(self, conceptual_data):
        """Transform logical data to physical storage format"""
        return {
            'format': 'binary',
            'compression': 'lz4',
            'data': conceptual_data,
            'page_size': 4096
        }

    def _from_physical_format(self, internal_data):
        """Transform physical storage to logical format"""
        return internal_data['data']

    def insert_external(self, user_data):
        """Insert data through external schema"""
        # Step 1: External to Conceptual
        conceptual = self.mapper.transform(user_data, 'external', 'conceptual')
        print(f"📊 Conceptual Level: {conceptual}")

        # Step 2: Conceptual to Internal (Physical)
        internal = self.mapper.transform(conceptual, 'conceptual', 'internal')
        print(f"💾 Internal Level: {internal}")

        # Store in physical storage
        table = conceptual['table']
        if table not in self.internal_data:
            self.internal_data[table] = []
        self.internal_data[table].append(internal)

        return "Data stored successfully with schema independence!"

# Demonstration
db = ThreeLevelDatabase()

print("=== Data Flow Through Three Schemas ===\n")

# User inserts data through their external view
user_input = {'name': 'John Doe', 'age': 20, 'gpa': 3.7}
print(f"📝 External Level (User Input): {user_input}")
print()

result = db.insert_external(user_input)
print()
print(result)
print()

print("=== Key Concept ===")
print("Users interact with their external view without knowing:")
print("• How data is logically structured (Conceptual)")
print("• How data is physically stored (Internal)")
print("The mapper handles all transformations automatically!")
